var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"좋아, 일단 피도 멎었고 의식도 회복했어.","JPN":"よし、とりあえずは血も止まって、意識も取り戻してる。","ENG":"Okay. The bleeding's stopped and she's regained consciousness.","TWN":"好了，血止住了，人也恢復意識了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"구급차 불렀어. 금방 올거야.","JPN":"救急車を呼んだわ。すぐ来るはずよ。","ENG":"I called the ambulance. It should be here soon.","TWN":"我叫了救護車，應該很快就到了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……코치.","JPN":"……コーチ。","ENG":"...Coach.","TWN":"……教練。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"라이카 양, 이제 정신이 드나?","JPN":"ライカ君、気がついたか？","ENG":"Laika, are you okay?","TWN":"萊卡，你醒了？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹… 이는……?","JPN":"おこ……ちゃまは……？","ENG":"What about... the kid...?","TWN":"小鬼…人呢……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 공격한 자를 쫓아갔네.","JPN":"君を攻撃した者を追いかけていった。","ENG":"She went after whoever attacked you.","TWN":"她去追攻擊你的人了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말해보게, 라이카 양. 어째서 저들이 자네를 공격한 거지?","JPN":"話してくれ、ライカ君。どうしてあの者たちが君を攻撃したんだ？","ENG":"Talk to me, Laika. Why did they attack you?","TWN":"萊卡，這是怎麼回事？那些人為什麼要攻擊你？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……출신 때문에.","JPN":"……出身。","ENG":"...My background.","TWN":"……因為出身。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내 출신 때문일 거야.","JPN":"たぶん私の出身のせいだと思う。","ENG":"It's because of where I'm from.","TWN":"他們攻擊我是因為我的出身。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"출신이라고?","JPN":"出身？","ENG":"Where you're from?","TWN":"因為你的出身？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"잠깐! 사장님! 저길 봐!","JPN":"ちょっと！　社長！　あそこを見て！","ENG":"Wait a minute! Boss! Look over there!","TWN":"老闆！你看！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘이랑 펠리세트가 향한 방향이야……!","JPN":"ノエルとフェリセットが向かった方向だよ……！","ENG":"It's where Noelle and Félicette went...!","TWN":"那是洛艾兒和費莉塞特所在的方向……！"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"벼, 벼락이라도 떨어진 걸까요?","JPN":"か、雷でも落ちたんでしょうか？","ENG":"I-is there lightning striking down?","TWN":"是打雷嗎？"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자연 현상 같은 게 아닐세.","JPN":"自然現象などではないな。","ENG":"It is not a natural phenomenon.","TWN":"應該不是自然現象。"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마도 어떤 에너지가 다른 에너지로 변환되는 과정 같아.","JPN":"たぶん、あるエネルギーが他のエネルギーへと変換されているんだろう。","ENG":"It appears to be the process of converting one type of energy into another.","TWN":"似乎是某種能量轉換成其他能量的過程。"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"에너지의 변환이라고요?","JPN":"エネルギーの変換？","ENG":"Converting energy?","TWN":"能量轉換？"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 하지만 저런 막대한 에너지를 한 번에 변환시키는 건 일반적인 방법으로는 불가능할 텐데?","JPN":"ああ。だが、あれほど莫大なエネルギーを一気に変換させることは一般的な方法では不可能なはずだ。","ENG":"Yes. But it should be virtually impossible to convert that much energy at once using conventional methods.","TWN":"沒錯，不過用一般的方法應該無法轉換這種強大的能量？"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이러고 있을 때가 아니야.","JPN":"こうしてる場合じゃない。","ENG":"We shouldn't be standing around like this then!","TWN":"現在不是說這些的時候。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저긴 노엘이랑 펠리세트가 향한 방향이라고.","JPN":"あそこはノエルとフェリセットが向かった方向だよ。","ENG":"That's where Noelle and Félicette went.","TWN":"那是洛艾兒和費莉塞特所在的方向欸！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 둘에게 무슨 일이 생겼을지도 몰라, 서두르자!","JPN":"二人に何かあったのかもしれない、急ごう！","ENG":"We need to hurry! Something might've happened to them!","TWN":"她們不知道是不是發生什麼事，動作快！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"라이카, 조금만 참아. 금방 병원에 도착할 거야.","JPN":"ライカ、ちょっとだけ我慢して。すぐ病院に着くから。","ENG":"Laika, hang in a little longer. You'll be in the hospital in no time.","TWN":"萊卡，你再忍耐一下，就快到醫院了。"},"stage":{"bg":"VEHICLE","bgm":"FX_CUTSCEN_BEEP3","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그냥, 뻥이라고 생각했는데…….","JPN":"ただの、ウソだと思ってたのに……","ENG":"I thought... she was just bluffing...","TWN":"我還以為她是騙人的……"},"stage":{"bg":"VEHICLE","bgm":"FX_CUTSCEN_BEEP3","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"라이카?","JPN":"ライカ？","ENG":"Laika?","TWN":"萊卡？"},"stage":{"bg":"VEHICLE","bgm":"FX_CUTSCEN_BEEP3","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"네 비장의 수단이라는 거…… 굉장하잖아, 꼬맹이…….","JPN":"あんたの切り札って……すごいじゃん、おこちゃま……","ENG":"Your ace up your sleeve... Quite impressive, kid...","TWN":"你的絕招……很厲害嘛，小鬼……"},"stage":{"bg":"VEHICLE","bgm":"FX_CUTSCEN_BEEP3","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};